// NEW: Check if basic mode is available
async function checkBasicMode() {
  try {
    const memoryDir = './memory';
    await fs.access(memoryDir);
    return true;
  } catch {
    // Create directory if it doesn't exist
    try {
      await fs.mkdir(memoryDir, { recursive: true });
      return true;
    } catch {
      return false;
    }
  }
}

